import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import Navbar from '../components/shared/Navbar';
import { StarDisplay } from '../components/shared/StarRating';
import { providerAPI, reviewAPI } from '../utils/api';
import { useAuth } from '../context/AuthContext';
import { format } from 'date-fns';
import toast from 'react-hot-toast';

const CAT_ICONS = { Electrician: '⚡', Plumber: '🔧', Carpenter: '🪚', Painter: '🎨', Cleaner: '🧹', ACTechnician: '❄️' };

export default function ProviderDetailPage() {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [provider, setProvider] = useState(null);
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [activeTab, setActiveTab] = useState('about');

  useEffect(() => {
    Promise.all([
      providerAPI.getById(id),
      reviewAPI.getByProvider(id),
    ]).then(([p, r]) => {
      setProvider(p.data.data);
      setReviews(r.data.data);
    }).catch(() => toast.error('Failed to load provider')).finally(() => setLoading(false));
  }, [id]);

  if (loading) return (
    <div><Navbar />
      <div className="page-container" style={{ paddingTop: 40 }}>
        <div className="skeleton" style={{ height: 200, marginBottom: 16 }} />
        <div className="skeleton" style={{ height: 400 }} />
      </div>
    </div>
  );

  if (!provider) return <div><Navbar /><div className="page-container"><p style={{ marginTop: 40, color: 'var(--text-secondary)' }}>Provider not found</p></div></div>;

  const u = provider.user || {};
  const initials = u.name?.split(' ').map(n => n[0]).join('').slice(0, 2).toUpperCase();

  return (
    <div style={{ minHeight: '100vh' }}>
      <Navbar />
      <div className="page-container" style={{ paddingTop: 32, paddingBottom: 48 }}>
        <div style={{ display: 'flex', gap: 24, flexWrap: 'wrap' }}>

          {/* ── Main Content ── */}
          <div style={{ flex: 1, minWidth: 300 }}>
            {/* Hero card */}
            <div className="card" style={{ marginBottom: 20, position: 'relative', overflow: 'hidden' }}>
              <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 4, background: 'linear-gradient(90deg, var(--accent), var(--success))' }} />
              <div style={{ display: 'flex', gap: 20, alignItems: 'flex-start', flexWrap: 'wrap' }}>
                <div style={{ position: 'relative' }}>
                  {u.avatar ? (
                    <img src={u.avatar} alt={u.name} style={{ width: 80, height: 80, borderRadius: '50%', objectFit: 'cover', border: '3px solid var(--border-light)' }} />
                  ) : (
                    <div style={{ width: 80, height: 80, borderRadius: '50%', background: 'var(--accent-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'var(--accent)', fontWeight: 800, fontSize: 26, fontFamily: 'var(--font-display)' }}>{initials}</div>
                  )}
                  <span style={{ position: 'absolute', bottom: 2, right: 2, width: 16, height: 16, borderRadius: '50%', background: provider.availability?.isAvailable ? 'var(--success)' : 'var(--text-muted)', border: '2px solid var(--bg-card)' }} />
                </div>

                <div style={{ flex: 1 }}>
                  <div style={{ display: 'flex', alignItems: 'center', gap: 10, flexWrap: 'wrap' }}>
                    <h1 style={{ fontSize: 24, fontWeight: 800 }}>{u.name}</h1>
                    {provider.verificationStatus === 'approved' && (
                      <span className="badge badge-success">✓ Verified</span>
                    )}
                    <span className="badge badge-accent">{CAT_ICONS[provider.serviceCategory]} {provider.serviceCategory}</span>
                  </div>
                  <div style={{ marginTop: 8 }}>
                    <StarDisplay rating={provider.rating?.average} count={provider.rating?.count} size={16} />
                  </div>
                  <div style={{ display: 'flex', gap: 20, marginTop: 12, flexWrap: 'wrap', fontSize: 13, color: 'var(--text-secondary)' }}>
                    <span>💼 {provider.experience} years experience</span>
                    <span>✅ {provider.completedJobs} jobs done</span>
                    <span>📍 {provider.location?.address}</span>
                  </div>
                </div>
              </div>
            </div>

            {/* Tabs */}
            <div className="tab-nav" style={{ marginBottom: 20 }}>
              {['about', 'skills', 'reviews'].map(t => (
                <button key={t} className={`tab-btn ${activeTab === t ? 'active' : ''}`}
                  onClick={() => setActiveTab(t)}>
                  {t === 'about' ? '📋 About' : t === 'skills' ? '🛠️ Skills' : `⭐ Reviews (${reviews.length})`}
                </button>
              ))}
            </div>

            {/* Tab Content */}
            {activeTab === 'about' && (
              <div className="card animate-fade">
                <h3 style={{ fontWeight: 700, marginBottom: 12 }}>About</h3>
                <p style={{ color: 'var(--text-secondary)', lineHeight: 1.7, fontSize: 14 }}>
                  {provider.bio || `${u.name} is a verified ${provider.serviceCategory} with ${provider.experience} years of experience. They are available for bookings and have completed ${provider.completedJobs} jobs on SkillBridge.`}
                </p>

                <div style={{ marginTop: 20, display: 'grid', gridTemplateColumns: 'repeat(2,1fr)', gap: 12 }}>
                  {[
                    { label: 'Working Hours', value: `${provider.availability?.workingHours?.start} – ${provider.availability?.workingHours?.end}` },
                    { label: 'Working Days', value: provider.availability?.workingDays?.join(', ') },
                    { label: 'Location', value: provider.location?.address },
                    { label: 'Status', value: provider.availability?.isAvailable ? '🟢 Available' : '🔴 Unavailable' },
                  ].map(item => (
                    <div key={item.label} style={{ background: 'var(--bg-secondary)', borderRadius: 'var(--radius)', padding: '12px 14px' }}>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: 1 }}>{item.label}</div>
                      <div style={{ fontSize: 14, color: 'var(--text-primary)', marginTop: 4, fontWeight: 500 }}>{item.value}</div>
                    </div>
                  ))}
                </div>
              </div>
            )}

            {activeTab === 'skills' && (
              <div className="card animate-fade">
                <h3 style={{ fontWeight: 700, marginBottom: 16 }}>Skills & Services</h3>
                <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
                  {provider.skills?.map(skill => (
                    <div key={skill} style={{ background: 'var(--bg-elevated)', border: '1px solid var(--border-light)', borderRadius: 10, padding: '8px 16px', fontSize: 14, color: 'var(--text-primary)', fontWeight: 500 }}>
                      {skill}
                    </div>
                  ))}
                </div>
                {provider.badges?.length > 0 && (
                  <div style={{ marginTop: 20 }}>
                    <h4 style={{ fontSize: 13, color: 'var(--text-muted)', textTransform: 'uppercase', letterSpacing: 1, marginBottom: 10 }}>Badges</h4>
                    <div style={{ display: 'flex', gap: 8 }}>
                      {provider.badges.map(b => <span key={b} className="badge badge-warning">🏆 {b}</span>)}
                    </div>
                  </div>
                )}
              </div>
            )}

            {activeTab === 'reviews' && (
              <div className="animate-fade">
                {reviews.length === 0 ? (
                  <div className="empty-state card"><div className="empty-state-icon">⭐</div><h3>No reviews yet</h3></div>
                ) : reviews.map(r => (
                  <div key={r._id} className="card" style={{ marginBottom: 12 }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start' }}>
                      <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                        <div style={{ width: 36, height: 36, borderRadius: '50%', background: 'var(--accent-dim)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 700, color: 'var(--accent)', fontSize: 13 }}>
                          {r.user?.name?.split(' ').map(n => n[0]).join('').slice(0, 2)}
                        </div>
                        <div>
                          <div style={{ fontWeight: 600, fontSize: 14 }}>{r.user?.name}</div>
                          <StarDisplay rating={r.rating} size={12} />
                        </div>
                      </div>
                      <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>
                        {format(new Date(r.createdAt), 'MMM d, yyyy')}
                      </div>
                    </div>
                    {r.comment && <p style={{ marginTop: 10, fontSize: 14, color: 'var(--text-secondary)', lineHeight: 1.6 }}>{r.comment}</p>}
                    {r.tags?.length > 0 && (
                      <div style={{ display: 'flex', gap: 6, flexWrap: 'wrap', marginTop: 8 }}>
                        {r.tags.map(tag => <span key={tag} className="badge badge-accent">{tag}</span>)}
                      </div>
                    )}
                    {r.providerReply && (
                      <div style={{ marginTop: 10, background: 'var(--bg-secondary)', borderLeft: '3px solid var(--accent)', padding: '8px 12px', borderRadius: '0 8px 8px 0', fontSize: 13, color: 'var(--text-secondary)' }}>
                        <strong style={{ color: 'var(--accent)' }}>Provider reply: </strong>{r.providerReply}
                      </div>
                    )}
                  </div>
                ))}
              </div>
            )}
          </div>

          {/* ── Booking Sidebar ── */}
          <div style={{ width: 280, flexShrink: 0 }}>
            <div className="card" style={{ position: 'sticky', top: 80 }}>
              <h3 style={{ fontWeight: 700, marginBottom: 4, fontSize: 16 }}>Book this Provider</h3>
              <div style={{ marginBottom: 16 }}>
                <div style={{ fontSize: 12, color: 'var(--text-muted)' }}>Price Range</div>
                <div style={{ fontSize: 22, fontWeight: 800, fontFamily: 'var(--font-display)', color: 'var(--success)' }}>
                  ₹{provider.priceRange?.min} – ₹{provider.priceRange?.max}
                </div>
              </div>

              {provider.availability?.isAvailable ? (
                <span className="badge badge-success" style={{ marginBottom: 16, display: 'inline-flex' }}>🟢 Available Now</span>
              ) : (
                <span className="badge badge-danger" style={{ marginBottom: 16, display: 'inline-flex' }}>🔴 Currently Unavailable</span>
              )}

              <button className="btn btn-primary" style={{ width: '100%', marginBottom: 10 }}
                onClick={() => user ? navigate(`/book/${provider._id}`) : navigate('/login')}>
                📅 Book Now
              </button>
              <button className="btn btn-secondary" style={{ width: '100%' }}
                onClick={() => user ? navigate(`/chat/${provider.user?._id}`) : navigate('/login')}>
                💬 Message
              </button>

              <div style={{ marginTop: 20, paddingTop: 16, borderTop: '1px solid var(--border)' }}>
                {[
                  { icon: '✅', text: 'Verified Professional' },
                  { icon: '🔒', text: 'Secure Payments' },
                  { icon: '⭐', text: 'Rated by customers' },
                ].map(i => (
                  <div key={i.text} style={{ display: 'flex', alignItems: 'center', gap: 8, fontSize: 12, color: 'var(--text-secondary)', marginBottom: 8 }}>
                    <span>{i.icon}</span><span>{i.text}</span>
                  </div>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
